_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"7.0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://es.wordpress.org/?p=1253489\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:363:\"Cada nueva versión de WordPress rinde homenaje a un artista que ha dejado una huella imborrable en el mundo de la música. En esta ocasión aquí tienes WordPress 7.0 «Armstrong», honrando al mismísimo «Satchmo», el gran músico de jazz Louis Armstrong. Conocido como el «primer gran solista de jazz», Louis Armstrong creó piezas que resaltaban [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:85685:\"\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0-scaled-1.jpg\"><img fetchpriority=\"high\" decoding=\"async\" width=\"2048\" height=\"1365\" src=\"https://es.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0-scaled-1.jpg\" alt=\"\" class=\"wp-image-1253491\" srcset=\"https://es.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0-scaled-1.jpg 2048w, https://es.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0-scaled-1-300x200.jpg 300w, https://es.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0-scaled-1-767x511.jpg 767w, https://es.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0-scaled-1-1024x683.jpg 1024w, https://es.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0-scaled-1-1536x1024.jpg 1536w\" sizes=\"(max-width: 2048px) 100vw, 2048px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Cada nueva versión de WordPress rinde homenaje a un artista que ha dejado una huella imborrable en el mundo de la música. </p>\n\n\n\n<p class=\"wp-block-paragraph\">En esta ocasión aquí tienes WordPress 7.0 «Armstrong», honrando al mismísimo «<strong>Satchmo</strong>», el gran músico de jazz Louis Armstrong.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Conocido como el «<strong>primer gran solista de jazz</strong>», Louis Armstrong creó piezas que resaltaban su profunda habilidad con la trompeta y, en el proceso, transformó el jazz de una forma de arte orquestal a estilo de arte solista. </p>\n\n\n\n<p class=\"wp-block-paragraph\">El maestro trompetista también impresionó al mundo con su inconfundible voz, introduciendo la improvisación en el jazz, influyendo en todos los artistas con los que trabajó y cambiando para siempre el panorama musical.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Louis Armstrong imprimió su sello personal al mundo del jazz. Con WordPress 7.0 «Armstrong» tú también vas a poder crear el tuyo.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¡Damos la bienvenida a WordPress 7.0!</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>WordPress 7.0 marca el inicio de una nueva era</strong>, sentando las bases para la <strong>inteligencia artificial en toda la experiencia de WordPress</strong>. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Con un escritorio más moderno e intuitivo, la versión 7.0 introduce herramientas de personalización y desarrollo mejoradas que inspiran la creatividad y permiten explorar un potencial ilimitado.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Ya seas creador, empresario o desarrollador, WordPress 7.0 te permite crear de una manera que sea exclusivamente tuya.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://es.wordpress.org/download/\">Descarga ya WordPress 7.0</a></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué hay por ahí dentro?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Explora las capacidades de la IA directamente en tu sitio web, todo gestionado desde un centro de control centralizado. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Navega sin problemas por el nuevo y elegante tema de administración implementado en todo el panel. Impulsa tu creatividad con nuevos bloques y herramientas de diseño, y accede a una amplia caja de herramientas para desarrolladores que te brinda más control que nunca, permitiéndote crear a tu manera.</p>\n\n\n\n<h3 class=\"wp-block-heading\">WordPress con inteligencia artificial integrada</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Todas las posibilidades están ahí, a tu alcance.</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Con la IA integrada en WordPress, el potencial es ilimitado. Un <strong>nuevo cliente de IA</strong> en el núcleo permite que WordPress se comunique con modelos de IA generativa, mientras que las conexiones se gestionan fácilmente desde un único panel de control. </p>\n\n\n\n<p class=\"wp-block-paragraph\">El cliente de IA, combinado con la <strong>API de capacidades</strong>, crea una potente combinación que introduce nuevas funcionalidades, automatización de flujos de trabajo y herramientas de creación en tu sitio web. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Instala el nuevo plugin de IA para ampliar aún más tus opciones: genera y edita imágenes, crea títulos o extractos, e incluso sugiere texto alternativo.</p>\n\n\n\n<p class=\"wp-block-paragraph\">La versión 7.0 también incluye un <strong>nuevo paquete de capacidades</strong> del lado del cliente, una contraparte en Javascript de la API de capacidades, con una interfaz de usuario integrada y una <strong>paleta de comandos</strong> que ofrece nuevas y amplias capacidades de IA híbridas.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2026/05/image-13.jpg\"><img decoding=\"async\" width=\"1360\" height=\"840\" src=\"https://es.wordpress.org/files/2026/05/image-13.jpg\" alt=\"\" class=\"wp-image-1253493\" srcset=\"https://es.wordpress.org/files/2026/05/image-13.jpg 1360w, https://es.wordpress.org/files/2026/05/image-13-767x474.jpg 767w, https://es.wordpress.org/files/2026/05/image-13-300x185.jpg 300w, https://es.wordpress.org/files/2026/05/image-13-1024x632.jpg 1024w\" sizes=\"(max-width: 1360px) 100vw, 1360px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Gestiona todas tus conexiones externas desde un centro de control centralizado en la <strong>pantalla de conectores</strong>. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Empieza a usarlas fácilmente con 3 configuraciones predefinidas o añade tus propias conexiones. Identifícate y <strong>empieza a usar las funciones de IA en tan solo unos clics</strong>.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2026/05/image-12.jpg\"><img decoding=\"async\" width=\"1360\" height=\"840\" src=\"https://es.wordpress.org/files/2026/05/image-12.jpg\" alt=\"\" class=\"wp-image-1253495\" srcset=\"https://es.wordpress.org/files/2026/05/image-12.jpg 1360w, https://es.wordpress.org/files/2026/05/image-12-767x474.jpg 767w, https://es.wordpress.org/files/2026/05/image-12-300x185.jpg 300w, https://es.wordpress.org/files/2026/05/image-12-1024x632.jpg 1024w\" sizes=\"(max-width: 1360px) 100vw, 1360px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Un WordPress con inteligencia artificial integrada promete un potencial infinito, listo para que descubrirlo.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Escritorio modernizado</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Mejora tu experiencia de administración</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">La versión 7.0 muestra <strong>un escritorio totalmente renovado</strong> con una nueva combinación de colores elegante y moderna, y acabados impecables en todas partes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Con <strong>transiciones fluidas</strong> y un acabado impecable que se adaptan a la perfección al cambiar de pantalla, sentirás que te mueves sin esfuerzo por el escritorio.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Con solo hacer clic en el <strong>nuevo acceso directo a la paleta de comandos</strong>, un icono de <code>⌘K</code> <code>/</code> <code>Ctrl+K</code> en la barra de administración superior, podrás <strong>acceder a tus herramientas favoritas desde cualquier lugar del escritorio</strong>.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2026/05/image-11.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1360\" height=\"840\" src=\"https://es.wordpress.org/files/2026/05/image-11.jpg\" alt=\"\" class=\"wp-image-1253497\" srcset=\"https://es.wordpress.org/files/2026/05/image-11.jpg 1360w, https://es.wordpress.org/files/2026/05/image-11-300x185.jpg 300w, https://es.wordpress.org/files/2026/05/image-11-767x474.jpg 767w, https://es.wordpress.org/files/2026/05/image-11-1024x632.jpg 1024w\" sizes=\"auto, (max-width: 1360px) 100vw, 1360px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Explora las <strong>tipografías desde un único lugar</strong>, independientemente del tema. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Instala, sube y gestiona tu colección de fuentes desde la nueva página específica para la gestión de fuentes, compatible con temas de bloques, híbridos y clásicos.<br></p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2026/05/image-10.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1360\" height=\"840\" src=\"https://es.wordpress.org/files/2026/05/image-10.jpg\" alt=\"\" class=\"wp-image-1253499\" srcset=\"https://es.wordpress.org/files/2026/05/image-10.jpg 1360w, https://es.wordpress.org/files/2026/05/image-10-300x185.jpg 300w, https://es.wordpress.org/files/2026/05/image-10-767x474.jpg 767w, https://es.wordpress.org/files/2026/05/image-10-1024x632.jpg 1024w\" sizes=\"auto, (max-width: 1360px) 100vw, 1360px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Revisa visualmente las versiones</strong> para ver los cambios de un vistazo, con marcadores que facilitan la selección de la versión. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Elige fácilmente la revisión que desees y restáurala al instante.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2026/05/image-9.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1360\" height=\"840\" src=\"https://es.wordpress.org/files/2026/05/image-9.jpg\" alt=\"\" class=\"wp-image-1253501\" srcset=\"https://es.wordpress.org/files/2026/05/image-9.jpg 1360w, https://es.wordpress.org/files/2026/05/image-9-300x185.jpg 300w, https://es.wordpress.org/files/2026/05/image-9-767x474.jpg 767w, https://es.wordpress.org/files/2026/05/image-9-1024x632.jpg 1024w\" sizes=\"auto, (max-width: 1360px) 100vw, 1360px\" /></a></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Diseña, crea, personaliza</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Una forma más sencilla de crear</strong> .</p>\n\n\n\n<p class=\"wp-block-paragraph\">Deja que WordPress sea tu musa con nuevos bloques, <strong>nuevas funcionalidades en los bloques y herramientas de diseño</strong> que añaden agilidad visual, control granular y mantienen cada elemento de tu sitio web acorde con tu marca, con toques novedosos.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Presenta tus ideas en una presentación de diapositivas con el <strong>nuevo bloque de galería</strong> y perfecciona tu código con el <strong>nuevo bloque de encabezado</strong>. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Ofrece una navegación clara con el <strong>nuevo bloque de migas de pan</strong> y añade más detalles a tus diseños con el <strong>nuevo bloque de iconos</strong>.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2026/05/image-8.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1360\" height=\"840\" src=\"https://es.wordpress.org/files/2026/05/image-8.jpg\" alt=\"\" class=\"wp-image-1253504\" srcset=\"https://es.wordpress.org/files/2026/05/image-8.jpg 1360w, https://es.wordpress.org/files/2026/05/image-8-1024x632.jpg 1024w, https://es.wordpress.org/files/2026/05/image-8-767x474.jpg 767w, https://es.wordpress.org/files/2026/05/image-8-300x185.jpg 300w\" sizes=\"auto, (max-width: 1360px) 100vw, 1360px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Los <strong>controles de adaptabilidad mejorados</strong> de la versión 7.0 hacen que tu sitio sea más fácil de usar. </p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Oculta y muestra bloques según el dispositivo</strong>, sin afectar a otras ventanas de visualización. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Ajusta los estilos para diferentes puntos de interrupción y personaliza cuáles son esos puntos de interrupción.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2026/05/image-7.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1360\" height=\"840\" src=\"https://es.wordpress.org/files/2026/05/image-7.jpg\" alt=\"\" class=\"wp-image-1253506\" srcset=\"https://es.wordpress.org/files/2026/05/image-7.jpg 1360w, https://es.wordpress.org/files/2026/05/image-7-767x474.jpg 767w, https://es.wordpress.org/files/2026/05/image-7-1024x632.jpg 1024w, https://es.wordpress.org/files/2026/05/image-7-300x185.jpg 300w\" sizes=\"auto, (max-width: 1360px) 100vw, 1360px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Diseña y crea tu <strong>menú superpuesto con bloques y patrones</strong>, totalmente personalizable con los estilos que deseas que vean tus visitantes. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Añade columnas, personaliza la tipografía o inserta tu propio botón de cierre en el menú. Empieza con una plantilla o crea tu propio menú desde cero.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2026/05/image-6.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1360\" height=\"840\" src=\"https://es.wordpress.org/files/2026/05/image-6.jpg\" alt=\"\" class=\"wp-image-1253508\" srcset=\"https://es.wordpress.org/files/2026/05/image-6.jpg 1360w, https://es.wordpress.org/files/2026/05/image-6-767x474.jpg 767w, https://es.wordpress.org/files/2026/05/image-6-300x185.jpg 300w, https://es.wordpress.org/files/2026/05/image-6-1024x632.jpg 1024w\" sizes=\"auto, (max-width: 1360px) 100vw, 1360px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Perfecciona el diseño y la maquetación de tu página con patrones que funcionan como una sola unidad, pero que se pueden separar para un control más individualizado. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Inserta tu patrón, intercambia elementos y personaliza con facilidad.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2026/05/image-5.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1360\" height=\"840\" src=\"https://es.wordpress.org/files/2026/05/image-5.jpg\" alt=\"\" class=\"wp-image-1253510\" srcset=\"https://es.wordpress.org/files/2026/05/image-5.jpg 1360w, https://es.wordpress.org/files/2026/05/image-5-300x185.jpg 300w, https://es.wordpress.org/files/2026/05/image-5-1024x632.jpg 1024w, https://es.wordpress.org/files/2026/05/image-5-767x474.jpg 767w\" sizes=\"auto, (max-width: 1360px) 100vw, 1360px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Personaliza cada detalle del contenido con <strong>CSS a nivel de bloque</strong>, directamente en tu entrada o página.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://es.wordpress.org/files/2026/05/image-4.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1360\" height=\"840\" src=\"https://es.wordpress.org/files/2026/05/image-4.jpg\" alt=\"\" class=\"wp-image-1253512\" srcset=\"https://es.wordpress.org/files/2026/05/image-4.jpg 1360w, https://es.wordpress.org/files/2026/05/image-4-300x185.jpg 300w, https://es.wordpress.org/files/2026/05/image-4-767x474.jpg 767w, https://es.wordpress.org/files/2026/05/image-4-1024x632.jpg 1024w\" sizes=\"auto, (max-width: 1360px) 100vw, 1360px\" /></a></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Caja de herramientas para desarrolladores</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Herramientas avanzadas para crear a tu manera</strong> .</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0 te permite crear sitios web más rápido, mejor, más robustos y más fáciles gracias a un amplio conjunto de <strong>API ampliadas y funcionalidades mejoradas</strong>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Crea <strong>bloques y patrones a nivel de servidor utilizando únicamente PHP</strong>, con registro automático en la API de bloques.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Descubre un <strong>editor de sitios más ampliable</strong>, con enrutamiento, validación de rutas y un nuevo paquete <code>wordpress/boot</code> que permite a los plugins crear páginas personalizadas para el editor de sitios.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Y mucho más</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Para obtener una descripción general completa de todas las nuevas características y mejoras de WordPress 7.0 visita la web con todas las novedades.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/download/releases/7-0\" target=\"_blank\" rel=\"noopener\">Descubre las novedades de la versión 7.0.</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Más información sobre WordPress 7.0</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://learn.wordpress.org/\">Aprende WordPress</a> es un recurso gratuito para usuarios de WordPress, tanto principiantes como experimentados. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Ofrece vídeos tutoriales sobre el uso de diversas características de WordPress, <a href=\"https://learn.wordpress.org/social-learning/\">talleres interactivos</a> para explorar temas en profundidad y lecciones planificadas para profundizar en áreas específicas de WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Consulta las&nbsp;<a href=\"https://wordpress.org/documentation/wordpress-version/version-7.0\">notas de la versión 7.0 de WordPress</a>&nbsp;para obtener información sobre la instalación, las mejoras, los problemas solucionados, los colaboradores de la versión, los recursos de aprendizaje y la lista de cambios en los archivos.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Explora la <a href=\"https://make.wordpress.org/core/2026/05/14/wordpress-7-0-field-guide/\">guía de campo de WordPress 7.0</a> y descubre los cambios de esta versión con notas detalladas para desarrolladores que te ayudarán a crear aplicaciones con WordPress.</p>\n\n\n\n<h2 class=\"wp-block-heading\">El equipo de lanzamiento de la versión 7.0</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Cada lanzamiento es fruto del trabajo de un equipo dedicado de colaboradores entusiastas que se aseguran de que todo funcione correctamente y sin contratiempos. </p>\n\n\n\n<p class=\"wp-block-paragraph\">El equipo que ha liderado la versión 7.0 es un grupo global y multidisciplinar de colaboradores siempre dispuestos a impulsar ideas, eliminar obstáculos y resolver problemas.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Responsable del lanzamiento: <a href=\"https://profiles.wordpress.org/matveb/\">Matias Ventura</a></li>\n\n\n\n<li>Coordinación del lanzamiento: <a href=\"https://profiles.wordpress.org/chaion07/\">Ahmed Kabir Chaion</a> , <a href=\"https://profiles.wordpress.org/amykamala/\">Amy Kamala</a> , <a href=\"https://profiles.wordpress.org/4thhubbard/\">Mary Hubbard</a></li>\n\n\n\n<li>Líderes técnicos: <a href=\"https://profiles.wordpress.org/ellatrix/\">Ella van Durpe</a> , <a href=\"https://profiles.wordpress.org/mukesh27/\">Mukesh Panchal</a> , <a href=\"https://profiles.wordpress.org/sergeybiryukov/\">Sergey Biryukov</a></li>\n\n\n\n<li>Líderes de triaje: <a href=\"https://profiles.wordpress.org/audrasjb/\">Jb Audras</a> , <a href=\"https://profiles.wordpress.org/juanmaguitar/\">JuanMa Garrido</a></li>\n\n\n\n<li>Responsables de las pruebas: <a href=\"https://profiles.wordpress.org/ankit-k-gupta/\">Ankit K Gupta</a> , <a href=\"https://profiles.wordpress.org/marybaum/\">Mary Baum</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Gracias a los colaboradores</h2>\n\n\n\n<p class=\"wp-block-paragraph\">La misión de WordPress es <a href=\"https://wordpress.org/about/\">democratizar la publicación</a> y encarnar las <a href=\"https://opensource.org/osd-annotated\">libertades que ofrece el código abierto</a>. Es una comunidad global y diversa de personas que colaboran para fortalecer el software respalda este esfuerzo.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0 refleja el incansable esfuerzo y la pasión de más de 900 colaboradores en países de todo el mundo. </p>\n\n\n\n<p class=\"wp-block-paragraph\">¡Esta versión también dio la bienvenida a más de <strong>279 nuevos colaboradores</strong>!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Su colaboración dio como resultado más de <strong>420 mejoras y correcciones</strong>, lo que garantizó una versión estable para todos, un testimonio del poder y la capacidad de la comunidad de código abierto de WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://profiles.wordpress.org/1000camels/\">1000camels</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/aakashverma1/\">Aakash Verma</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/aaronrobertshaw/\">Aaron Robertshaw</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/abdullah17/\">Abdullah Kaludi</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/abduremon/\">Abdur Rahman Emon</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/acmoifr/\">acmoifr</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/dannythedog/\">Adam</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/adamsilverstein/\">Adam Silverstein</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/zieladam/\">Adam Zieliński</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/oztaser/\">Adil Öztaşer</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/adithyanaik/\">adithyanaik</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/iamadisingh/\">Aditya Singh</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/adnanhyder/\">Adnan Hyder Pervez</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/adnanlimdi/\">adnan.limdi</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/adrmf25/\">adrmf25</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/afwebdev/\">afwebdev</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/agnieszkaszuba/\">Agnieszka Szuba</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/elazzabi/\">Ahmed</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/chaion07/\">Ahmed Kabir Chaion</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/ajitbohra/\">Ajit Bohra</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/wildworks/\">Aki Hamano</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/akshat2802/\">Akshat Kakkad</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/aljullu/\">Albert Juhí Lluveras</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/alecrust/\">Alec Rust</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/alecgeatches/\">alecgeatches</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/xknown/\">Alex Concha</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/akirk/\">Alex Kirk</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/ajlende/\">Alex Lende</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/alexstine/\">Alex Stine</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/albigdd/\">Alexander Bigga</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/aliaghdam/\">Ali Aghdam</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/mrfoxtalbot/\">Alvaro Gómez ·&nbsp;</a><a href=\"https://profiles.wordpress.org/amanandhishoe/\">amanandhishoe</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/alh0319/\">Amber Hinds</a>&nbsp;·&nbsp;Ames&nbsp;<a href=\"https://profiles.wordpress.org/amesplant/\">Plant</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/amibe/\">Sitios web de Amibe</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/amin7/\">Amin</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/amitraj2203/\">Amit Raj</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/amykamala/\">​​Amy Kamala</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/altf4falt/\">Anand Rajaram</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/anastis/\">anastis Sourgoutsidis</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/anlino/\">Anders Norún</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/afercia/\">Andrea Fercia</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/awetz583/\">Andrea Roenning</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/andraganescu/\">Andrei Draganescu</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/aduth/\">Andrew Duthie</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/nacin/\">Andrew Nacin</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/azaozz/\">Andrew Ozz</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/andrewryno/\">Andrew Ryno</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/andrewserong/\">Andrew Serong</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/eatingrules/\">Andrew Wilder</a>&nbsp;·&nbsp;